  "constraints": {
    "cannot_push_past_date": "2026-10-02",
    "preserve_assessment_window": true
  },
  "deliverables": ["time_blocks_UNIT-01.json"],
  "timeout_seconds": 300,
  "created_at": "2026-09-22T16:00:00Z",
  "status": "queued"
}
Result JSON:
{
  "task_id": "PLAN-ADJUST-UNIT-01",
  "status": "done",
